/* Kill Jira's transition:all so color changes appear instant */
[data-testid="platform-board-kit.ui.card.card"],
[data-testid="platform-board-kit.ui.card.card"] *,
[data-testid="software-board.board-container.board.card-container.card-with-icc"] { transition: none !important; }

/* DEFAULT styles on virtual list items — li>div exists BEFORE React hydrates the full card */
{{#priorityColors}}
[data-testid="software-board.board-container.board.virtual-board.fast-virtual-list.fast-virtual-list-wrapper"] > li > div { border-left: 4px solid #e2b203 !important; }
{{/priorityColors}}
{{#workTypeColors}}
[data-testid="software-board.board-container.board.virtual-board.fast-virtual-list.fast-virtual-list-wrapper"] > li > div { background: rgba(87, 163, 241, 0.07) !important; }
{{/workTypeColors}}

/* Priority overrides — JS sets data-domo-priority, these override the default */
{{#priorityColors}}
[data-testid="platform-board-kit.ui.card.card"][data-domo-priority="Highest"],
[data-testid="platform-board-kit.ui.card.card"][data-domo-priority="Critical"] { border-left-color: #ef5c48 !important; }
[data-testid="platform-board-kit.ui.card.card"][data-domo-priority="High"] { border-left-color: #f18d13 !important; }
[data-testid="platform-board-kit.ui.card.card"][data-domo-priority="Medium"] { border-left-color: #e2b203 !important; }
[data-testid="platform-board-kit.ui.card.card"][data-domo-priority="Low"] { border-left-color: #4bce97 !important; }
[data-testid="platform-board-kit.ui.card.card"][data-domo-priority="Lowest"] { border-left-color: #8590a2 !important; }
{{/priorityColors}}

/* Type overrides — CSS :has() for when img loads, JS attribute as backup */
{{#workTypeColors}}
[data-testid="platform-board-kit.ui.card.card"]:has(img[alt="Bug"]),
[data-testid="platform-board-kit.ui.card.card"][data-domo-type="Bug"] { background: rgba(239, 92, 72, 0.12) !important; }
[data-testid="platform-board-kit.ui.card.card"]:has(img[alt="Story"]),
[data-testid="platform-board-kit.ui.card.card"][data-domo-type="Story"] { background: rgba(75, 206, 151, 0.10) !important; }
[data-testid="platform-board-kit.ui.card.card"]:has(img[alt="Task"]),
[data-testid="platform-board-kit.ui.card.card"]:has(img[alt="Sub-task"]),
[data-testid="platform-board-kit.ui.card.card"][data-domo-type="Task"],
[data-testid="platform-board-kit.ui.card.card"][data-domo-type="Sub-task"] { background: rgba(87, 163, 241, 0.10) !important; }
[data-testid="platform-board-kit.ui.card.card"]:has(img[alt="Epic"]),
[data-testid="platform-board-kit.ui.card.card"][data-domo-type="Epic"] { background: rgba(144, 107, 244, 0.10) !important; }
{{/workTypeColors}}

/* Flagged override */
{{#flaggedHighlight}}
[data-testid="platform-board-kit.ui.card.card"][data-domo-flagged="true"] { border: 2px solid #ef5c48 !important; box-shadow: 0 0 6px rgba(239, 92, 72, 0.3) !important; }
{{/flaggedHighlight}}

