(function() {
  var enablePriority = api.options.priorityColors;
  var enableType = api.options.workTypeColors;
  var enableFlagged = api.options.flaggedHighlight;
  if (!enablePriority && !enableType && !enableFlagged) return;

  var issueCache = {};

  function applyToCard(card, data) {
    if (enablePriority && data.priority) card.setAttribute('data-domo-priority', data.priority);
    if (enableType && data.type) card.setAttribute('data-domo-type', data.type);
    if (enableFlagged && data.flagged) card.setAttribute('data-domo-flagged', 'true');
  }

  function getIssueKey(card) {
    var keyEl = card.querySelector('[data-testid="platform-card.common.ui.key.key"]');
    return keyEl ? keyEl.textContent.trim() : null;
  }

  function prefetchProject() {
    var match = location.pathname.match(/\/projects\/([A-Z0-9]+)/);
    if (!match) return;
    var project = match[1];
    fetch('/rest/api/3/search/jql', {
      method: 'POST',
      credentials: 'same-origin',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ jql: 'project=' + project, fields: ['priority', 'issuetype', 'customfield_10021'], maxResults: 100 })
    })
    .then(function(r) { return r.json(); })
    .then(function(data) {
      if (!data.issues) return;
      data.issues.forEach(function(issue) {
        var flagField = issue.fields.customfield_10021;
        issueCache[issue.key] = {
          priority: issue.fields.priority ? issue.fields.priority.name : null,
          type: issue.fields.issuetype ? issue.fields.issuetype.name : null,
          flagged: !!(flagField && (flagField === true || (Array.isArray(flagField) && flagField.length)))
        };
      });
      processCards();
    })
    .catch(function() {});
  }

  function processCards() {
    var cards = document.querySelectorAll('[data-testid="platform-board-kit.ui.card.card"]');
    cards.forEach(function(card) {
      var key = getIssueKey(card);
      if (!key) return;
      var currentKey = card.getAttribute('data-domo-key');
      if (currentKey === key) return;
      card.setAttribute('data-domo-key', key);
      card.removeAttribute('data-domo-priority');
      card.removeAttribute('data-domo-type');
      card.removeAttribute('data-domo-flagged');
      if (issueCache[key]) applyToCard(card, issueCache[key]);
    });
  }

  prefetchProject();
  processCards();

  // Scroll listener on board container — fires during scroll with no delay
  var scrollEl = document.querySelector('[data-testid="platform-board-kit.ui.board.scroll.board-scroll"]');
  if (scrollEl) {
    var onScroll = function() { requestAnimationFrame(processCards); };
    scrollEl.addEventListener('scroll', onScroll, { passive: true });
    api.onCleanup(function() { scrollEl.removeEventListener('scroll', onScroll); });
  }

  // MutationObserver as backup for non-scroll DOM changes
  var observer = new MutationObserver(function() { processCards(); });
  observer.observe(document.body, { childList: true, subtree: true });
  api.onCleanup(function() { observer.disconnect(); });
})();
